import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { useMusic } from '../../context/MusicContext';
import { Play, Music, CheckCircle2, Circle, X, Library } from 'lucide-react';

const Home = () => {
  const navigate = useNavigate();
  const [songs, setSongs] = useState([]);
  const [playlists, setPlaylists] = useState([]); 
  const { playMusic } = useMusic();
  
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);

  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
    if (loggedInUser) fetchUserPlaylists();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải bài hát:", err); }
  };

  const fetchUserPlaylists = async () => {
    try {
      const userId = loggedInUser._id || loggedInUser.id;
      const res = await axios.get(`http://localhost:5000/api/playlists/user/${userId}`);
      setPlaylists(res.data);
    } catch (err) { console.error("Lỗi tải playlist:", err); }
  };

  const handleStartCreatePlaylist = () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Nhập tên cho Playlist mới tại IAMNHAC:");
    if (!title) return;
    setNewPlaylistTitle(title);
    setIsSelecting(true);
    setSelectedSongIds([]);
  };

  const toggleSongSelection = (songId) => {
    if (selectedSongIds.includes(songId)) {
      setSelectedSongIds(selectedSongIds.filter(id => id !== songId));
    } else {
      setSelectedSongIds([...selectedSongIds, songId]);
    }
  };

  const handleSavePlaylist = async () => {
    if (selectedSongIds.length === 0) {
      if (!window.confirm("Bạn chưa chọn bài hát nào. Vẫn muốn tạo playlist trống?")) return;
    }
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: newPlaylistTitle,
        userId: loggedInUser._id || loggedInUser.id,
        songIds: selectedSongIds
      });
      alert(`Thành công! IAMNHAC đã tạo playlist "${newPlaylistTitle}"`);
      setIsSelecting(false);
      setSelectedSongIds([]);
    } catch (err) { alert("Lỗi khi lưu Playlist."); }
  };


  return (
    <div style={{ padding: '30px 60px', background: '#f8f9fa', minHeight: '100vh', paddingBottom: '120px' }}>
      
      {isSelecting && (
        <div style={selectionBar}>
          <span>Đang tạo: <b>{newPlaylistTitle}</b> ({selectedSongIds.length} bài)</span>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={handleSavePlaylist} style={btnConfirm}>LƯU PLAYLIST</button>
            <button onClick={() => { setIsSelecting(false); setSelectedSongIds([]); }} style={btnCancel}><X size={20}/></button>
          </div>
        </div>
      )}

      <header style={headerStyle}>
        <h1 style={{ color: '#1db954', display: 'flex', alignItems: 'center', gap: '10px' }}><Music size={40}/> IAMNHAC</h1>
        {!isSelecting && (
          <button onClick={() => {
            const t = prompt("Nhập tên playlist mới:");
            if(t) { setNewPlaylistTitle(t); setIsSelecting(true); setSelectedSongIds([]); }
          }} style={btnCreate}>+ TẠO PLAYLIST</button>
        )}
      </header>

      {playlists.length > 0 && !isSelecting && (
        <section style={{ marginBottom: '40px' }}>
          <h2 style={sectionTitle}><Library size={22}/> Playlist của bạn</h2>
          <div style={playlistGrid}>
            {playlists.map(pl => (
              <div key={pl._id} style={plCard} onClick={() => navigate(`/playlist/${pl._id}`)}>
                <div style={plIcon}><Music color="#fff" size={30}/></div>
                <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{pl.title}</div>
                <div style={{ fontSize: '12px', color: '#888' }}>
                  {/* Dùng toán tử optional chaining để tránh lỗi length */}
                  {pl.songs?.length || 0} bài hát
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      <section>
        <h2 style={sectionTitle}>Khám phá nhạc mới</h2>
        <div style={songGrid}>
          {songs.map((song, index) => {
            const isSelected = selectedSongIds.includes(song._id);
            return (
              <div key={song._id} style={sCard(isSelected)} onClick={() => {
                if(isSelecting) {
                  setSelectedSongIds(prev => 
                    prev.includes(song._id) ? prev.filter(id => id !== song._id) : [...prev, song._id]
                  );
                } else {
                  playMusic(songs, index);
                }
              }}>
                <div style={{ position: 'relative' }}>
                  <img src={`http://localhost:5000${song.imageUrl}`} style={sImg} alt={song.title} />
                  {isSelecting ? (
                    <div style={checkOverlay}>
                      {isSelected ? <CheckCircle2 color="#1db954" fill="#fff"/> : <Circle color="#fff"/>}
                    </div>
                  ) : (
                    <div style={playIconOverlay}><Play fill="#fff" size={20}/></div>
                  )}
                </div>
                <div style={{ marginTop: '10px', fontWeight: 'bold' }}>{song.title}</div>
                <div style={{ fontSize: '12px', color: '#666' }}>{song.artist}</div>
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

/* --- STYLES (GIỮ NGUYÊN) --- */
const selectionBar = { position: 'fixed', top: 0, left: 0, right: 0, background: '#1db954', color: '#fff', padding: '15px 60px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', zIndex: 1000 };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const btnCreate = { background: '#000', color: '#fff', border: 'none', padding: '12px 25px', borderRadius: '30px', fontWeight: 'bold', cursor: 'pointer' };
const btnConfirm = { background: '#fff', color: '#1db954', border: 'none', padding: '10px 20px', borderRadius: '20px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { background: 'rgba(255,255,255,0.2)', border: 'none', color: '#fff', width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const sectionTitle = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px', fontSize: '22px', fontWeight: 'bold' };
const playlistGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '20px' };
const plCard = { background: '#fff', padding: '15px', borderRadius: '15px', cursor: 'pointer', boxShadow: '0 4px 10px rgba(0,0,0,0.05)', transition: 'transform 0.2s' };
const plIcon = { height: '130px', background: 'linear-gradient(135deg, #1db954, #191414)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '10px' };
const songGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '25px' };
const sCard = (sel) => ({ background: '#fff', padding: '15px', borderRadius: '15px', cursor: 'pointer', border: sel ? '3px solid #1db954' : '3px solid transparent', transition: '0.2s', boxShadow: '0 4px 10px rgba(0,0,0,0.05)' });
const sImg = { width: '100%', aspectRatio: '1/1', objectFit: 'cover', borderRadius: '10px' };
const checkOverlay = { position: 'absolute', top: 10, right: 10, background: 'rgba(0,0,0,0.5)', borderRadius: '50%', padding: '2px' };
const playIconOverlay = { position: 'absolute', bottom: 10, right: 10, background: '#1db954', width: '40px', height: '40px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0.9 };

export default Home;
